// ── Login ──
const Login = ({ onLogin, onInvite }) => {
  const [email, setEmail] = useState("");
  const [pw, setPw] = useState("");
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);

  const go = () => {
    setErr(""); setLoading(true);
    setTimeout(() => {
      setLoading(false);
      const e = email.trim().toLowerCase();
      if (e === ADMIN_EMAIL.toLowerCase() && pw === ADMIN_PASSWORD) { onLogin("admin", null); return; }
      const m = INIT_MEMBERS.find(m => m.email === e && m.pw === pw);
      if (m) { onLogin("member", m); return; }
      setErr("Email ou senha incorretos.");
    }, 500);
  };

  return (
    <div style={{ minHeight:"100vh", background:C.bg, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:24 }}>
      <div style={{ width:"100%", maxWidth:340 }}>
        {/* logo */}
        <div style={{ textAlign:"center", marginBottom:28 }}>
          <img src={LOGO_SRC} alt="Ner Israel" style={{ height:60, width:"auto", objectFit:"contain", display:"block", margin:"0 auto 10px" }} />
          <div style={{ color:C.gray, fontSize:12 }}>Programa de Conquistas</div>
        </div>

        <div style={{ background:C.panel, border:`1px solid ${C.border}`, borderRadius:10, padding:"22px 20px" }}>
          <Inp label="Email" value={email} onChange={e=>{setEmail(e.target.value);setErr("")}} onKeyDown={e=>e.key==="Enter"&&go()} placeholder="seu@email.com" type="email" />
          <Inp label="Senha" value={pw} onChange={e=>{setPw(e.target.value);setErr("")}} onKeyDown={e=>e.key==="Enter"&&go()} placeholder="••••••••" type="password" />
          {err && <div style={{ color:"#FF8080", fontSize:12, marginBottom:12, marginTop:-8 }}>{err}</div>}
          <button onClick={go} style={{ width:"100%", background:`linear-gradient(135deg,${C.gold},${C.goldL})`, color:C.bg, border:"none", padding:"11px", borderRadius:7, fontWeight:800, fontSize:14, cursor:"pointer" }}>
            {loading ? "..." : "Entrar →"}
          </button>
        </div>

        <div style={{ textAlign:"center", marginTop:16 }}>
          <button onClick={onInvite} style={{ background:"transparent", color:C.grayL, border:`1px solid ${C.border}`, borderRadius:7, padding:"8px 20px", fontSize:13, cursor:"pointer" }}>
            Solicitar Convite
          </button>
        </div>
        <div style={{ textAlign:"center", marginTop:14, color:C.border, fontSize:10 }}>
          demo: voce@email.com / 123
        </div>
      </div>
    </div>
  );
};

// ── Request invite ──
const RequestInvite = ({ onBack, onDone }) => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [msg, setMsg] = useState("");
  const [sent, setSent] = useState(false);

  const go = () => {
    if (!name || !email) return;
    setSent(true);
    setTimeout(() => onDone({ name, email, msg }), 2200);
  };

  if (sent) return (
    <div style={{ minHeight:"100vh", background:C.bg, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", textAlign:"center", padding:24 }}>
      <div style={{ fontSize:40, marginBottom:16 }}>📧</div>
      <div style={{ color:C.white, fontSize:18, fontWeight:600, marginBottom:8 }}>Solicitação enviada!</div>
      <div style={{ color:C.gray, fontSize:13, maxWidth:280, lineHeight:1.5 }}>O admin receberá um email. Você será notificado em <strong style={{color:C.goldL}}>{email}</strong> quando aprovado.</div>
    </div>
  );

  return (
    <div style={{ minHeight:"100vh", background:C.bg, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:24 }}>
      <div style={{ width:"100%", maxWidth:340 }}>
        <div style={{ textAlign:"center", marginBottom:24 }}>
          <img src={LOGO_SRC} alt="" style={{ height:50, objectFit:"contain", display:"block", margin:"0 auto 10px" }} />
          <div style={{ color:C.white, fontSize:16, fontWeight:600 }}>Solicitar Convite</div>
          <div style={{ color:C.gray, fontSize:12, marginTop:4 }}>O admin decidirá se libera seu acesso.</div>
        </div>
        <div style={{ background:C.panel, border:`1px solid ${C.border}`, borderRadius:10, padding:"20px" }}>
          <Inp label="Nome *" value={name} onChange={e=>setName(e.target.value)} placeholder="Nome completo" />
          <Inp label="Email *" value={email} onChange={e=>setEmail(e.target.value)} placeholder="seu@email.com" type="email" />
          <div style={{ marginBottom:14 }}>
            <div style={{ fontSize:10, color:C.gray, letterSpacing:1.2, textTransform:"uppercase", marginBottom:5 }}>Mensagem (opcional)</div>
            <textarea value={msg} onChange={e=>setMsg(e.target.value)} placeholder="Por que deseja participar?" style={{ width:"100%", boxSizing:"border-box", background:C.bg, border:`1px solid ${C.border}`, color:C.white, padding:"9px 12px", borderRadius:6, fontSize:13, resize:"none", height:70, fontFamily:"sans-serif" }} />
          </div>
          <div style={{ background:C.gold+"11", border:`1px solid ${C.gold}33`, borderRadius:6, padding:"8px 12px", marginBottom:14, fontSize:12, color:C.goldL }}>
            📧 Envio para admin@nerIsrael.com
          </div>
          <button onClick={go} disabled={!name||!email} style={{ width:"100%", background: name&&email ? `linear-gradient(135deg,${C.gold},${C.goldL})` : C.border, color:C.bg, border:"none", padding:"11px", borderRadius:7, fontWeight:800, fontSize:14, cursor: name&&email?"pointer":"default", opacity: name&&email?1:0.5 }}>
            Enviar →
          </button>
        </div>
        <button onClick={onBack} style={{ display:"block", width:"100%", marginTop:12, background:"transparent", color:C.gray, border:"none", cursor:"pointer", fontSize:13, padding:"8px" }}>← Voltar</button>
      </div>
    </div>
  );
};

// ── Points modal ──
const PointsModal = ({ onClose, onSubmit }) => {
  const [sel, setSel] = useState([]);
  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);
  const [hol, setHol] = useState(false);
  const toggle = id => setSel(s => s.includes(id) ? s.filter(x=>x!==id) : [...s,id]);
  const base = sel.reduce((s,id)=>s+(ACTS.find(a=>a.id===id)?.pts||0),0);
  const total = hol ? base*2 : base;

  return (
    <div style={{ position:"fixed", inset:0, background:"#000A", display:"flex", alignItems:"flex-end", justifyContent:"center", zIndex:999 }} onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div style={{ background:C.panel, border:`1px solid ${C.border}`, borderRadius:"12px 12px 0 0", padding:"24px 20px", width:"100%", maxWidth:560, maxHeight:"88vh", overflowY:"auto" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
          <span style={{ fontSize:16, fontWeight:700, color:C.white }}>Solicitar Pontos</span>
          <button onClick={onClose} style={{ background:"transparent", border:"none", color:C.gray, fontSize:20, cursor:"pointer" }}>×</button>
        </div>

        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:16 }}>
          <div>
            <div style={{ fontSize:10, color:C.gray, letterSpacing:1, textTransform:"uppercase", marginBottom:5 }}>Data</div>
            <input type="date" value={date} onChange={e=>setDate(e.target.value)} style={{ width:"100%", boxSizing:"border-box", background:C.bg, border:`1px solid ${C.border}`, color:C.white, padding:"8px 10px", borderRadius:6, fontSize:12 }} />
          </div>
          <div onClick={()=>setHol(h=>!h)} style={{ background: hol?C.gold+"18":C.bg, border:`1px solid ${hol?C.gold+"66":C.border}`, borderRadius:6, padding:"8px 12px", cursor:"pointer", display:"flex", alignItems:"center", gap:8, marginTop:20 }}>
            <div style={{ width:16, height:16, borderRadius:3, border:`2px solid ${hol?C.gold:C.border}`, background:hol?C.gold:"transparent", display:"flex", alignItems:"center", justifyContent:"center", fontSize:10, color:C.bg, fontWeight:900, flexShrink:0 }}>{hol&&"✓"}</div>
            <div>
              <div style={{ fontSize:12, color: hol?C.goldL:C.white }}>🎉 Feriado/Férias</div>
              {hol && <div style={{ fontSize:10, color:C.gold }}>2× pontos!</div>}
            </div>
          </div>
        </div>

        {["shacharit","mincha","other","bonus"].map(cat=>(
          <div key={cat} style={{ marginBottom:16 }}>
            <div style={{ fontSize:10, color:C.gold, letterSpacing:1, textTransform:"uppercase", marginBottom:8 }}>{CAT[cat]}</div>
            {ACTS.filter(a=>a.cat===cat).map(act=>(
              <div key={act.id} onClick={()=>toggle(act.id)} style={{ display:"flex", alignItems:"center", justifyContent:"space-between", background: sel.includes(act.id)?C.gold+"14":C.bg, border:`1px solid ${sel.includes(act.id)?C.gold+"55":C.border}`, borderRadius:7, padding:"9px 12px", cursor:"pointer", marginBottom:6, transition:"all .1s" }}>
                <div>
                  <div style={{ fontSize:13, color: sel.includes(act.id)?C.goldL:C.white }}>{act.label}</div>
                  <div style={{ fontSize:11, color:C.gray }}>{act.sub}</div>
                </div>
                <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                  <span style={{ background:C.gold+"18", color:C.gold, padding:"2px 8px", borderRadius:20, fontSize:11, fontWeight:700 }}>+{hol?act.pts*2:act.pts}</span>
                  <div style={{ width:16, height:16, borderRadius:3, border:`2px solid ${sel.includes(act.id)?C.gold:C.border}`, background:sel.includes(act.id)?C.gold:"transparent", display:"flex", alignItems:"center", justifyContent:"center", fontSize:10, color:C.bg, fontWeight:900, flexShrink:0 }}>{sel.includes(act.id)&&"✓"}</div>
                </div>
              </div>
            ))}
          </div>
        ))}

        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:8 }}>
          <div>
            <div style={{ fontSize:10, color:C.gray }}>Total</div>
            <div style={{ fontSize:28, fontWeight:900, color:C.gold }}>+{total} pts</div>
          </div>
          <button onClick={()=>sel.length>0&&onSubmit(total,sel.map(id=>ACTS.find(a=>a.id===id)?.label).join(", "))} style={{ background: sel.length>0?`linear-gradient(135deg,${C.gold},${C.goldL})`:C.border, color:C.bg, border:"none", padding:"11px 22px", borderRadius:7, fontWeight:800, fontSize:14, cursor:sel.length>0?"pointer":"default", opacity:sel.length>0?1:0.4 }}>
            Enviar →
          </button>
        </div>
      </div>
    </div>
  );
};

